    reaction::memory::StackMonitor::enableMonitoring();

    // Initialize stack monitor
    reaction::memory::StackMonitor::initialize();

    // Get usage statistics before guard
    auto statsBefore = reaction::memory::StackMonitor::getUsageStats();

    // Check allocation permissions before guard
    bool templateAllowed = reaction::memory::StackMonitor::isTemplateAllocationAllowed();
    bool runtimeAllowed = reaction::memory::StackMonitor::isRuntimeAllocationAllowed();

    // Create large StackGuard
    constexpr size_t largeSize = MEMORY_STACK_GUARD_SIZE_MAX;
    reaction::memory::StackGuard<largeSize> guard;

    // Check if guard was successfully created
    bool guardHeld = guard.wasAllocated();

    // Check if allocations are blocked while guard is held
    bool templateBlocked = !reaction::memory::StackMonitor::isTemplateAllocationAllowed();
    bool runtimeBlocked = !reaction::memory::StackMonitor::isRuntimeAllocationAllowed();
    bool allocationBlockedWhileGuardHeld = templateBlocked || runtimeBlocked;

    // Get usage statistics after guard
    auto statsAfter = reaction::memory::StackMonitor::getUsageStats();

    return StackLimitSnapshot{
        statsBefore,
        statsAfter,
        templateAllowed,
        runtimeAllowed,
        guardHeld,
        allocationBlockedWhileGuardHeld
    };
}

